1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
13	
14	const CURSED_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	const LOYALTY_THRESHOLD_YEARS = 2;
19	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	
22	const COMPONENT_TYPES = ["rune", "moonstone"];
23	const BLOCK_SIZE = 3;
24	const BLOCK_PREMIUM = 60;
25	
26	const componentPremium = (type: string, count: number): number =>
27	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
28	
29	const itemSurcharge = (item: any): number => {
30	  const base = basePremiumForType(item.type);
31	  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
32	    + (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
33	};
34	
35	const calculateQuotePremium = (items: any[], customer: any, stepIndex: number): number => {
36	  const componentCounts: Record<string, number> = {};
37	  let policyBasePremium = 0;
38	  let itemSurcharges = 0;
39	  for (const item of items) {
40	    if (COMPONENT_TYPES.includes(item.type)) {
41	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
42	    } else {
43	      policyBasePremium += basePremiumForType(item.type);
44	      itemSurcharges += itemSurcharge(item);
45	    }
46	  }
47	  for (const [type, count] of Object.entries(componentCounts)) {
48	    policyBasePremium += componentPremium(type, count);
49	  }
50	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
51	    ? policyBasePremium * LOYALTY_DISCOUNT_RATE
52	    : 0;
53	  const followUpDiscount = stepIndex > 0 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
54	  const premium = policyBasePremium + itemSurcharges - loyaltyDiscount
55	    + policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE - followUpDiscount;
56	  return Math.ceil(premium + PROCESSING_FEE);
57	};
58	
59	export const processScenario = (scenario: any): any => ({
60	  results: scenario.steps.map((step: any, index: number) => ({
61	    premium: calculateQuotePremium(step.items, scenario.customer, index),
62	  })),
63	});
